import { WorkflowEntrypoint, type WorkflowStep, type WorkflowEvent } from "cloudflare:workers";

export type OnboardingParams = { userId: string; email: string };

export class OnboardingWorkflow extends WorkflowEntrypoint<Env, OnboardingParams> {
  async run(event: WorkflowEvent<OnboardingParams>, step: WorkflowStep) {
    await step.do("create workspace", async () => {
      console.log("create workspace", event.payload.userId);
    });

    await step.do("send welcome email", async () => {
      console.log("send welcome email", event.payload.email);
    });
  }
}

const checks = [
  "Install provider package and configure env",
  "Run the local example path",
  "Add auth, retries, and audit events before production",
];

export default function CloudflareWorkflowsPage() {
  return (
    <main className="flex flex-col gap-6 p-6">
      <div>
        <h1 className="text-2xl font-semibold">Cloudflare Workflows</h1>
        <p className="text-muted-foreground">Workers-native durable steps for onboarding, billing sync, and backfills.</p>
      </div>
      <div className="grid gap-3">
        {checks.map((check) => (
          <div key={check} className="rounded-lg border p-4 text-sm">{check}</div>
        ))}
      </div>
    </main>
  );
}
